const webhookBody = $('Webhook - POST ai-chat').item.json.body;
const org_id = webhookBody.organization_id;
const conversation_id = webhookBody.conversation_id || null;
const userMessage = webhookBody.message;

// Brand profile
const brandProfiles = $('Supabase - Get Brand Profile').all().map(i => i.json);
const brand = Array.isArray(brandProfiles[0]) ? brandProfiles[0][0] : (brandProfiles[0] || {});

// Programs
const programsData = $('Supabase - Get Active Programs').all().map(i => i.json);
const programs = Array.isArray(programsData[0]) ? programsData[0] : programsData;

// Analytics
const analyticsData = $('Supabase - Get Analytics 7d').all().map(i => i.json);
const analytics = Array.isArray(analyticsData[0]) ? analyticsData[0] : analyticsData;

// Build programs summary
let programsSummary = 'Aucun programme en cours.';
if (programs.length > 0) {
  programsSummary = programs.map(p =>
    `- ${p.title} (${p.status}) : ${p.posts_per_week} posts/sem, du ${p.start_date} au ${p.end_date}`
  ).join('\n');
}

// Build analytics summary
let analyticsSummary = 'Pas encore de données.';
if (analytics.length > 0) {
  const totalLikes = analytics.reduce((s, a) => s + (a.likes_count || 0), 0);
  const totalComments = analytics.reduce((s, a) => s + (a.comments_count || 0), 0);
  const totalImpressions = analytics.reduce((s, a) => s + (a.impressions_count || 0), 0);
  const avgEng = analytics.filter(a => a.engagement_rate).length > 0
    ? (analytics.reduce((s, a) => s + (a.engagement_rate || 0), 0) / analytics.filter(a => a.engagement_rate).length).toFixed(2)
    : '0';
  analyticsSummary = `7 derniers jours : ${analytics.length} posts analysés. ${totalLikes} likes, ${totalComments} commentaires, ${totalImpressions} impressions. Engagement moyen : ${avgEng}%.`;
}

// System prompt
const systemPrompt = `Tu es l'assistant personnel de communication de ${brand.company_name || 'cette entreprise'}.

Ton rôle : accompagner le client dans la planification de ses campagnes LinkedIn.

Profil de l'entreprise :
- Entreprise : ${brand.company_name || '?'} — ${brand.description || '?'}
- Secteur : ${brand.industry || '?'}
- Audience : ${brand.target_audience || '?'}
- Ton : ${JSON.stringify(brand.tone || [])}
- Mots-clés : ${JSON.stringify(brand.keywords || [])}

Programmes en cours :
${programsSummary}

Performances récentes :
${analyticsSummary}

Règles impératives :
- Sois proactif et concret. Propose des titres de posts précis.
- Parle en français.
- Quand le client valide un programme, génère OBLIGATOIREMENT ce format JSON :
[PROGRAM_PROPOSAL]
{ "title": "...", "duration_weeks": N, "posts_per_week": N, "posts": [{"title": "...", "week": 1, "theme": "...", "day_of_week": "monday"}, ...] }
[/PROGRAM_PROPOSAL]
- Ne génère ce format QUE quand le client dit explicitement qu'il valide.`;

// Fetch or init conversation
let existingMessages = [];
let convId = conversation_id;

if (conversation_id) {
  const supabaseUrl = $env.POSTPILOT_SUPABASE_URL;
  const res = await $helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/ai_conversations?id=eq.${conversation_id}&select=messages&limit=1`,
    headers: {
      'apikey': $env.POSTPILOT_SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${$env.POSTPILOT_SUPABASE_SERVICE_ROLE_KEY}`,
      'Accept': 'application/json'
    }
  });
  const rows = Array.isArray(res) ? res : [res];
  if (rows.length > 0 && rows[0].messages) {
    existingMessages = Array.isArray(rows[0].messages) ? rows[0].messages : JSON.parse(rows[0].messages);
  }
}

// Append user message
existingMessages.push({ role: 'user', content: userMessage, timestamp: new Date().toISOString() });

// Build Claude messages format
const claudeMessages = existingMessages.map(m => ({ role: m.role, content: m.content }));

return [{ json: {
  org_id,
  conv_id: convId,
  system_prompt: systemPrompt,
  claude_messages: claudeMessages,
  existing_messages: existingMessages
} }];

const buildNode = $('Code - Build Conversation & Prompt').item.json;
const claudeResp = $json;

const org_id = buildNode.org_id;
let conv_id = buildNode.conv_id;
const existingMessages = buildNode.existing_messages || [];

// Extract reply text
const replyText = claudeResp.content && claudeResp.content[0] ? claudeResp.content[0].text : '';

// Append assistant message
existingMessages.push({ role: 'assistant', content: replyText, timestamp: new Date().toISOString() });

// Parse PROGRAM_PROPOSAL if present
const extracted_items = [];
const proposalMatch = replyText.match(/\[PROGRAM_PROPOSAL\]([\s\S]*?)\[\/PROGRAM_PROPOSAL\]/);
if (proposalMatch) {
  try {
    const proposalData = JSON.parse(proposalMatch[1].trim());
    extracted_items.push({ type: 'program', data: proposalData, validated: false });
  } catch (e) {
    // ignore parse error
  }
}

// Save conversation to Supabase
const supabaseUrl = $env.POSTPILOT_SUPABASE_URL;
const headers = {
  'apikey': $env.POSTPILOT_SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.POSTPILOT_SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

let savedConv;
if (conv_id) {
  // Update existing
  savedConv = await $helpers.httpRequest({
    method: 'PATCH',
    url: `${supabaseUrl}/rest/v1/ai_conversations?id=eq.${conv_id}`,
    headers,
    body: JSON.stringify({
      messages: existingMessages,
      extracted_items,
      updated_at: new Date().toISOString()
    })
  });
  savedConv = Array.isArray(savedConv) ? savedConv[0] : { id: conv_id };
} else {
  // Create new conversation
  const title = existingMessages[0]?.content?.slice(0, 60) || 'Nouvelle conversation';
  savedConv = await $helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/ai_conversations`,
    headers,
    body: JSON.stringify({
      organization_id: org_id,
      context: 'program_planning',
      title,
      messages: existingMessages,
      extracted_items,
      is_active: true
    })
  });
  savedConv = Array.isArray(savedConv) ? savedConv[0] : savedConv;
  conv_id = savedConv?.id || conv_id;
}

return [{ json: {
  reply: replyText,
  conversation_id: conv_id,
  extracted_items
} }];
